8	---------------------------------------------------------------------------------------------------
9	-- Description
10	---------------------------------------------------------------------------------------------------
11	-- This entity implements a simple I2C-master (multi master capable)
12	--
13	-- Documentation:
14	-- https://github.com/open-logic/open-logic/blob/main/doc/intf/olo_intf_i2c_master.md
15	--
16	-- Note: The link points to the documentation of the latest release. If you
17	--       use an older version, the documentation might not match the code.
18	
19	---------------------------------------------------------------------------------------------------
20	-- Package for Interface Simplification
21	---------------------------------------------------------------------------------------------------
22	library ieee;
23	    use ieee.std_logic_1164.all;
24	    use ieee.numeric_std.all;
25	    use ieee.math_real.all;
26	
27	library work;
28	    use work.olo_base_pkg_math.all;
29	    use work.olo_base_pkg_logic.all;
30	    use work.olo_base_pkg_string.all;
31	
32	package olo_intf_i2c_master_pkg is
33	
34	    constant I2cCmd_Start_c    : std_logic_vector(2 downto 0) := "000";
35	    constant I2cCmd_Stop_c     : std_logic_vector(2 downto 0) := "001";
36	    constant I2cCmd_RepStart_c : std_logic_vector(2 downto 0) := "010";
37	    constant I2cCmd_Send_c     : std_logic_vector(2 downto 0) := "011";
38	    constant I2cCmd_Receive_c  : std_logic_vector(2 downto 0) := "100";
39	
40	end package;
41	
42	---------------------------------------------------------------------------------------------------
43	-- Libraries
44	---------------------------------------------------------------------------------------------------
45	library ieee;
46	    use ieee.std_logic_1164.all;
47	    use ieee.numeric_std.all;
48	    use ieee.math_real.all;
49	
50	library work;
51	    use work.olo_base_pkg_math.all;
52	    use work.olo_base_pkg_logic.all;
53	    use work.olo_base_pkg_attribute.all;
54	    use work.olo_base_pkg_string.all;
55	    use work.olo_intf_i2c_master_pkg.all;
56	
57	---------------------------------------------------------------------------------------------------
58	-- Entity
59	---------------------------------------------------------------------------------------------------
60	entity olo_intf_i2c_master is
61	    generic (
62	        ClkFrequency_g      : real;
63	        I2cFrequency_g      : real    := 100.0e3;
64	        ClkDivBits_g        : natural := 0;
65	        BusBusyTimeout_g    : real    := 1.0e-3;
66	        CmdTimeout_g        : real    := 1.0e-3;
67	        InternalTriState_g  : boolean := true;
68	        DisableAsserts_g    : boolean := false
69	    );
70	    port (
71	        -- Control Signals
72	        Clk             : in    std_logic;
73	        Rst             : in    std_logic;
74	        -- Command Interface
75	        Cmd_Ready       : out   std_logic;
76	        Cmd_Valid       : in    std_logic;
77	        Cmd_Command     : in    std_logic_vector(2 downto 0);
78	        Cmd_Data        : in    std_logic_vector(7 downto 0);
79	        Cmd_Ack         : in    std_logic;
80	        Cmd_ClkDiv      : in    std_logic_vector(ClkDivBits_g - 1 downto 0) := (others => '0');
81	        -- Response Interface
82	        Resp_Valid      : out   std_logic;
83	        Resp_Command    : out   std_logic_vector(2 downto 0);
84	        Resp_Data       : out   std_logic_vector(7 downto 0);
85	        Resp_Ack        : out   std_logic;
86	        Resp_ArbLost    : out   std_logic;
87	        Resp_SeqErr     : out   std_logic;
88	        -- Status Interface
89	        Status_BusBusy  : out   std_logic;
90	        Status_CmdTo    : out   std_logic;
91	        -- I2c Interface with internal Tri-State
92	        I2c_Scl         : inout std_logic;
93	        I2c_Sda         : inout std_logic;
94	        -- I2c Interface with external Tri-State
95	        I2c_Scl_i       : in    std_logic                                   := '0';
96	        I2c_Scl_o       : out   std_logic;
97	        I2c_Scl_t       : out   std_logic;
98	        I2c_Sda_i       : in    std_logic                                   := '0';
99	        I2c_Sda_o       : out   std_logic;
100	        I2c_Sda_t       : out   std_logic
101	    );
102	end entity;
103	
104	---------------------------------------------------------------------------------------------------
105	-- Architecture
106	---------------------------------------------------------------------------------------------------
107	architecture rtl of olo_intf_i2c_master is
108	
109	    -- *** Constants ***
110	    constant EntityName_c         : string  := "olo_intf_i2c_master";
111	    constant BusyTimoutLimit_c    : integer := integer(ClkFrequency_g * BusBusyTimeout_g) - 1;
112	    constant QuarterPeriodLimit_c : integer := integer(ceil(ClkFrequency_g / I2cFrequency_g / 4.0)) - 1;
113	    constant CmdTimeoutLimit_c    : integer := integer(ClkFrequency_g * CmdTimeout_g) - 1;
114	
115	    -- *** Types ***
116	    type Fsm_t is (
117	        BusIdle_s, BusBusy_s, MinIdle_s, Start1_s, Start2_s, WaitCmd_s, WaitLowCenter_s,
118	        Stop1_s, Stop2_s, Stop3_s, RepStart1_s, DataBit1_s, DataBit2_s, DataBit3_s, DataBit4_s, ArbitLost_s
119	    );
120	
121	    -- *** Two Process Method ***
122	    type TwoProcess_r is record
123	        Status_BusBusy : std_logic;
124	        Cmd_Ready      : std_logic;
125	        SclLast        : std_logic;
126	        SdaLast        : std_logic;
127	        BusBusyToCnt   : unsigned(log2ceil(BusyTimoutLimit_c + 1) - 1 downto 0);
128	        TimeoutCmdCnt  : unsigned(log2ceil(CmdTimeoutLimit_c + 1) - 1 downto 0);
129	        QuartPeriodCnt : unsigned(log2ceil(QuarterPeriodLimit_c + 1) - 1 downto 0);
130	        QPeriodTick    : std_logic;
131	        ClkDivCnt      : unsigned(ClkDivBits_g - 1 downto 0);
132	        CmdClkDivLatch : unsigned(ClkDivBits_g - 1 downto 0);
133	        CmdTypeLatch   : std_logic_vector(Cmd_Command'range);
134	        CmdAckLatch    : std_logic;
135	        Fsm            : Fsm_t;
136	        SclOut         : std_logic;
137	        SdaOut         : std_logic;
138	        Resp_Valid     : std_logic;
139	        Resp_Ack       : std_logic;
140	        Resp_SeqErr    : std_logic;
141	        Resp_Data      : std_logic_vector(7 downto 0);
142	        Resp_ArbLost   : std_logic;
143	        BitCnt         : unsigned(3 downto 0); -- 8 Data + 1 Ack = 9 = 4 bits
144	        ShReg          : std_logic_vector(8 downto 0);
145	        CmdTimeout     : std_logic;
146	        Status_CmdTo   : std_logic;
147	    end record;
148	
149	    signal r, r_next : TwoProcess_r;
150	
151	    -- Required to Fix Vivado 2018.2 Synthesis Bug! Is fixed in Vivado 2019.1 according to Xilinx.
152	    attribute dont_touch of r : signal is DontTouch_SuppressChanges_c;
153	
154	    -- Tri-state buffer muxing
155	    signal I2cScl_Input : std_logic;
156	    signal I2cSda_Input : std_logic;
157	    signal I2cScl_Sync  : std_logic;
158	    signal I2cSda_Sync  : std_logic;
159	
160	begin
161	
162	    -----------------------------------------------------------------------------------------------
163	    -- Combinatorial Proccess
164	    -----------------------------------------------------------------------------------------------
165	    p_comb : process (all) is
166	        variable v                     : TwoProcess_r;
167	        variable SdaRe_v, SdaFe_v      : std_logic;
168	        variable I2cStart_v, I2cStop_v : std_logic;
169	    begin
170	        -- *** hold variables stable ***
171	        v := r;
172	
173	        -- *** Edge Detection ***
174	        -- SclRe_v   := not r.SclLast and I2cScl_Sync;
175	        -- SclFe_v   := r.SclLast and not I2cScl_Sync;
176	        SdaRe_v   := not r.SdaLast and I2cSda_Sync;
177	        SdaFe_v   := r.SdaLast and not I2cSda_Sync;
178	        v.SclLast := I2cScl_Sync;
179	        v.SdaLast := I2cSda_Sync;
180	
181	        -- *** Start/Stop Detection ***
182	        I2cStart_v := r.SclLast and I2cScl_Sync and SdaFe_v;
183	        I2cStop_v  := r.SclLast and I2cScl_Sync and SdaRe_v;
184	
185	        -- *** Quarter Period Counter ***
186	        -- The FSM may overwrite the counter in some cases!
187	        v.QPeriodTick := '0';
188	        if (r.Fsm = BusIdle_s) or (r.Fsm = BusBusy_s) then
189	            v.QuartPeriodCnt := (others => '0');
190	            v.ClkDivCnt      := to_unsigned(1, ClkDivBits_g);
191	        elsif r.ClkDivCnt >= r.CmdClkDivLatch or ClkDivBits_g = 0 then
192	            v.ClkDivCnt := to_unsigned(1, ClkDivBits_g);
193	            if r.QuartPeriodCnt = QuarterPeriodLimit_c then
194	                v.QuartPeriodCnt := (others => '0');
195	                v.QPeriodTick    := '1';
196	            else
197	                v.QuartPeriodCnt := r.QuartPeriodCnt + 1;
198	            end if;
199	        else
200	            v.ClkDivCnt := r.ClkDivCnt + 1;
201	        end if;
202	
203	        -- *** Command Timeout Detection ***
204	        if r.Fsm = WaitCmd_s then
205	            -- Timeout
206	            if r.TimeoutCmdCnt = CmdTimeoutLimit_c then
207	                v.CmdTimeout := '1';
208	            -- Count
209	            else
210	                v.TimeoutCmdCnt := r.TimeoutCmdCnt + 1;
211	            end if;
212	        -- In all states except waiting for command, reset the timer
213	        else
214	            v.TimeoutCmdCnt := (others => '0');
215	        end if;
216	
217	        -- *** Latch Command ***
218	        if (r.Cmd_Ready = '1') and (Cmd_Valid = '1') then
219	            v.CmdTypeLatch := Cmd_Command;
220	            v.CmdAckLatch  := Cmd_Ack;
221	        end if;
222	
223	        -- *** Default Values ***
224	        v.Resp_Valid   := '0';
225	        v.Resp_Ack     := not r.ShReg(0);
226	        v.Resp_Data    := r.ShReg(8 downto 1);
227	        v.Resp_SeqErr  := '0';
228	        v.Resp_ArbLost := '0';
229	        v.Status_CmdTo := '0';
230	        v.Cmd_Ready    := '0';
231	
232	        -- *** FSM ***
233	        case r.Fsm is
234	
235	            -- Bus Idle
236	            when BusIdle_s =>
237	                -- Default Outputs
238	                v.Cmd_Ready    := '1';
239	                v.BusBusyToCnt := (others => '0');
240	                v.SclOut       := '1';
241	                v.SdaOut       := '1';
242	                v.CmdTimeout   := '0';
243	
244	                -- Detect Bus Busy by Start Command
245	                if (r.Cmd_Ready = '1') and (Cmd_Valid = '1') then
246	                    -- Everyting else than START commands is ignored and an error is printed in this case
247	                    -- synthesis translate_off
248	                    assert (Cmd_Command = I2cCmd_Start_c) or DisableAsserts_g
249	                        report errorMessage(EntityName_c, "In idle state, only I2cCmd_Start_c commands are allowed!")
250	                        severity error;
251	                    -- synthesis translate_on
252	                    v.CmdTypeLatch := Cmd_Command;
253	                    if Cmd_Command = I2cCmd_Start_c then
254	                        v.Fsm       := Start1_s;
255	                        v.Cmd_Ready := '0';
256	                        -- Sample the clock division value
257	                        if ClkDivBits_g > 0 and Cmd_ClkDiv /= zerosVector(Cmd_ClkDiv'length) then
258	                            v.CmdClkDivLatch := unsigned(Cmd_ClkDiv);
259	                        else
260	                            v.CmdClkDivLatch := to_unsigned(1, ClkDivBits_g);
261	                        end if;
262	                    else
263	                        v.Resp_Valid  := '1';
264	                        v.Resp_SeqErr := '1';
265	                    end if;
266	                -- Detect Busy from other master
267	                elsif (I2cScl_Sync = '0') or (I2cStart_v = '1') then
268	                    v.Fsm       := BusBusy_s;
269	                    v.Cmd_Ready := '0';
270	                end if;
271	
272	            -- Bus Busy by other master
273	            when BusBusy_s =>
274	                -- Bus released
275	                if I2cStop_v = '1' then
276	                    v.Fsm := MinIdle_s;
277	                end if;
278	                -- Timeout Handling
279	                if I2cScl_Sync = '0' then
280	                    v.BusBusyToCnt := (others => '0');
281	                elsif r.BusBusyToCnt = BusyTimoutLimit_c then
282	                    v.Fsm := BusIdle_s;
283	                else
284	                    v.BusBusyToCnt := r.BusBusyToCnt + 1;
285	                end if;
286	
287	                v.SclOut := '1';
288	                v.SdaOut := '1';
289	
290	            -- Ensure that SDA stays low for at least half a clock period after the bus was released
291	            when MinIdle_s =>
292	                if r.QPeriodTick = '1' then
293	                    v.Fsm := BusIdle_s;
294	                end if;
295	
296	                v.SclOut := '1';
297	                v.SdaOut := '1';
298	
299	            -- Start Condition
300	            --------------------------------------------------------------------------------
301	            -- State    BusBusy_s   Start1_s   Start2_s   WaitCmd_s
302	            -- __________________________________
303	            -- Scl ...                                  |___________ ...
304	            -- _______________________
305	            -- SDA ...                       |______________________ ...
306	            when Start1_s =>
307	                if r.QPeriodTick = '1' then
308	                    v.Fsm := Start2_s;
309	                end if;
310	
311	                -- Handle Clock Stretching in case of a repeated start (slave keeps SCL low)
312	                if I2cScl_Sync = '0' and r.CmdTypeLatch = I2cCmd_RepStart_c then
313	                    v.QuartPeriodCnt := (others => '0');
314	                    v.ClkDivCnt      := to_unsigned(1, ClkDivBits_g);
315	                end if;
316	
317	                -- Handle Arbitration (other master transmits start condition first)
318	                if I2cSda_Sync = '0' then
319	                    v.Fsm := ArbitLost_s;
320	                end if;
321	
322	                v.SclOut := '1';
323	                v.SdaOut := '1';
324	
325	            when Start2_s =>
326	                if r.QPeriodTick = '1' then
327	                    v.Fsm        := WaitCmd_s;
328	                    v.Resp_Valid := '1';
329	                end if;
330	                v.SclOut := '1';
331	                v.SdaOut := '0';
332	
333	            -- Wait for user command (in first half of SCL low phase)
334	
335	            when WaitCmd_s =>
336	                -- Default Outputs
337	                v.Cmd_Ready := '1';
338	                v.SclOut    := '0';
339	
340	                -- All commands except START are allowed, START commands are ignored
341	                if (r.Cmd_Ready = '1') and (Cmd_Valid = '1') then
342	                    -- synthesis translate_off
343	                    assert (Cmd_Command = I2cCmd_Stop_c) or (Cmd_Command = I2cCmd_RepStart_c) or
344	                           (Cmd_Command = I2cCmd_Send_c) or (Cmd_Command = I2cCmd_Receive_c) or DisableAsserts_g
345	                        report errorMessage(EntityName_c, "In WaitCmd_s state, I2cCmd_Start_c commands are not allowed!")
346	                        severity error;
347	                    -- synthesis translate_on
348	                    if (Cmd_Command = I2cCmd_Stop_c) or (Cmd_Command = I2cCmd_RepStart_c) or
349	                       (Cmd_Command = I2cCmd_Send_c) or (Cmd_Command = I2cCmd_Receive_c) then
350	                        v.Fsm       := WaitLowCenter_s;
351	                        v.Cmd_Ready := '0';
352	                    else
353	                        v.Resp_Valid  := '1';
354	                        v.Resp_SeqErr := '1';
355	                    end if;
356	                    -- Latch data (used for SEND)
357	                    v.ShReg := Cmd_Data & '0';
358	                -- Command timeout - In this case send a STOP to free the bus
359	                elsif r.CmdTimeout = '1' then
360	                    v.Fsm          := WaitLowCenter_s;
361	                    v.Cmd_Ready    := '0';
362	                    v.Status_CmdTo := '1';
363	                end if;
364	
365	            -- Wait for center of SCL low phase (after user command arrived)
366	            when WaitLowCenter_s =>
367	                -- State Handling
368	                v.SclOut := '0';
369	                v.BitCnt := (others => '0');
370	
371	                -- Switch to commands
372	                if r.QPeriodTick = '1' then
373	                    -- In timeout case, send a STOP to free the bus
374	                    if r.CmdTimeout = '1' then
375	                        v.Fsm := Stop1_s;
376	                    -- Else, go to requested command
377	                    else
378	
379	                        case r.CmdTypeLatch is
380	                            when I2cCmd_Stop_c => v.Fsm := Stop1_s;
381	                            when I2cCmd_RepStart_c => v.Fsm := RepStart1_s;
382	                            when I2cCmd_Send_c => v.Fsm := DataBit1_s;
383	                            when I2cCmd_Receive_c => v.Fsm := DataBit1_s;
384	                            -- coverage off
385	                            when others => null; -- unreacable code
386	                            -- coverage on
387	                        end case;
388	
389	                    end if;
390	                end if;
391	
392	            -- Repeated Start Condition
393	            --------------------------------------------------------------------------------
394	            -- State       RepStart1_s   Start1_s   Start2_s   WaitCmd_s
395	            -- _____________________
396	            -- Scl ..._________________|                     |___________ ...
397	            -- __________________________
398	            -- SDA ...XXX                          |_____________________ ...
399	            -- States after RepStart1_s are shared with normal start condition
400	
401	            when RepStart1_s =>
402	                if r.QPeriodTick = '1' then
403	                    -- The rest of the sequence is same as for START
404	                    v.Fsm := Start1_s;
405	
406	                    -- Handle Arbitration other master prvents repeating start by transmitting 0
407	                    if I2cSda_Sync = '0' then
408	                        v.Fsm := ArbitLost_s;
409	                    end if;
410	                end if;
411	                v.SclOut := '0';
412	                v.SdaOut := '1';
413	
414	            -- Data Bit
415	            --------------------------------------------------------------------------------
416	            -- State  DataBit1_s   DataBit2_s   DataBit3_s   WaitCmd_s / DataBit4_s
417	            -- _________________________
418	            -- Scl ...___________|                         |___________ ...
419	            -- -- SDA ...XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX
420	            -- The DataBit1_s is the second half of the SCL low period. So the
421	            -- SDA Line is set at the beginning of DataBit1_s. After the SCL high period
422	            -- of the last bit, the state is changed to WaitCmd_s. Otherwise the first half of the SCL low
423	            -- period is executed (DataBit4_s) before the next bit starts (DataBit1_s)
424	
425	            when DataBit1_s =>
426	                if r.QPeriodTick = '1' then
427	                    v.Fsm := DataBit2_s;
428	                end if;
429	                v.SclOut := '0';
430	
431	                -- Send Operation
432	                if r.CmdTypeLatch = I2cCmd_Send_c then
433	                    -- For Ack, receive data
434	                    if r.BitCnt = 8 then
435	                        v.SdaOut := '1';
436	                    -- .. else send data
437	                    else
438	                        v.SdaOut := r.ShReg(8);
439	                    end if;
440	                -- Receive Operatiom
441	                else
442	                    -- Ack Handling
443	                    if r.BitCnt = 8 then
444	                        if r.CmdAckLatch = '1' then
445	                            v.SdaOut := '0';
446	                        else
447	                            v.SdaOut := '1';
448	                        end if;
449	                    -- .. else tri-state for receiving
450	                    else
451	                        v.SdaOut := '1';
452	                    end if;
453	                end if;
454	
455	            when DataBit2_s =>
456	                if r.QPeriodTick = '1' then
457	                    v.Fsm := DataBit3_s;
458	                    -- Shift register in the middle of the CLK pulse
459	                    v.ShReg := r.ShReg(7 downto 0) & I2cSda_Sync;
460	                end if;
461	                v.SclOut := '1';
462	
463	                -- Handle Clock Stretching (slave keeps SCL low)
464	                if I2cScl_Sync = '0' then
465	                    v.QuartPeriodCnt := (others => '0');
466	                    v.ClkDivCnt      := to_unsigned(1, ClkDivBits_g);
467	                end if;
468	
469	                -- Handle Arbitration for Sending (only databits, not ack)
470	                if (r.CmdTypeLatch = I2cCmd_Send_c) and (r.BitCnt /= 8) then
471	                    if I2cSda_Sync /= r.SdaOut then
472	                        v.Fsm := ArbitLost_s;
473	                    end if;
474	                -- Receiving does not need arbitration since slave addresses are unique
475	                end if;
476	
477	            when DataBit3_s =>
478	                if r.QPeriodTick = '1' then
479	                    -- Command Done after 9 bits (8 Data + 1 Ack)
480	                    if r.BitCnt = 8 then
481	                        v.Fsm        := WaitCmd_s;
482	                        v.Resp_Valid := '1';
483	                    -- Else goto next bit
484	                    else
485	                        v.Fsm := DataBit4_s;
486	                    end if;
487	                end if;
488	                v.SclOut := '1';
489	
490	                -- Handle Arbitration for Sending (only databits, not ack)
491	                if (r.CmdTypeLatch = I2cCmd_Send_c) and (r.BitCnt /= 8) then
492	                    if I2cSda_Sync /= r.SdaOut then
493	                        v.Fsm := ArbitLost_s;
494	                    end if;
495	                -- Receiving does not need arbitration since slave addresses are unique
496	                end if;
497	
498	            when DataBit4_s =>
499	                if r.QPeriodTick = '1' then
500	                    v.Fsm    := DataBit1_s;
501	                    v.BitCnt := r.BitCnt + 1;
502	                end if;
503	                v.SclOut := '0';
504	
505	            -- Stop Condition
506	            --------------------------------------------------------------------------------
507	            -- State   WaitCmd_s   Stop1_s   Stop2_s   Stop3_s   BusIdle_s
508	            -- _____________________
509	            -- Scl ..._____________________|                     |__________ ...
510	            -- _____________________
511	            -- SDA ...XXXXXXXXXXXX____________________|                      ...
512	
513	            when Stop1_s =>
514	                if r.QPeriodTick = '1' then
515	                    v.Fsm := Stop2_s;
516	                end if;
517	                v.SclOut := '0';
518	                v.SdaOut := '0';
519	
520	            when Stop2_s =>
521	                if r.QPeriodTick = '1' then
522	                    v.Fsm := Stop3_s;
523	                end if;
524	                v.SclOut := '1';
525	                v.SdaOut := '0';
526	
527	                -- Handle Clock Stretching (slave keeps SCL low)
528	                if I2cScl_Sync = '0' then
529	                    v.QuartPeriodCnt := (others => '0');
530	                    v.ClkDivCnt      := to_unsigned(1, ClkDivBits_g);
531	                end if;
532	
533	            when Stop3_s =>
534	                if r.QPeriodTick = '1' then
535	                    -- Handle Arbitration
536	                    if I2cSda_Sync = '0' then
537	                        v.Fsm := ArbitLost_s;
538	                    -- Else the STOP was successful
539	                    else
540	                        v.Fsm := BusIdle_s;
541	                        -- Send response only if the stop was not generated by a timeout
542	                        if r.CmdTimeout = '0' then
543	                            v.Resp_Valid := '1';
544	                        end if;
545	                    end if;
546	                end if;
547	                v.SclOut := '1';
548	                v.SdaOut := '1';
549	
550	            -- Send Response in case the arbitration was lost
551	            when ArbitLost_s =>
552	                v.Fsm          := BusBusy_s;
553	                v.Resp_Valid   := '1';
554	                v.Resp_Ack     := '0';
555	                v.Resp_ArbLost := '1';
556	                v.SclOut       := '1';
557	                v.SdaOut       := '1';
558	
559	            -- coverage off
560	            when others => null; -- unreacable code
561	            -- coverage on
562	        end case;
563	
564	        -- *** Bus Busy ***
565	        if r.Fsm = BusIdle_s then
566	            v.Status_BusBusy := '0';
567	        else
568	            v.Status_BusBusy := '1';
569	        end if;
570	
571	        -- *** assign signal ***
572	        r_next <= v;
573	    end process;
574	
575	    -----------------------------------------------------------------------------------------------
576	    -- Outputs
577	    -----------------------------------------------------------------------------------------------
578	    Status_BusBusy <= r.Status_BusBusy;
579	    Cmd_Ready      <= r.Cmd_Ready;
580	    Resp_Valid     <= r.Resp_Valid;
581	    Resp_Command   <= r.CmdTypeLatch;
582	    Resp_ArbLost   <= r.Resp_ArbLost;
583	    Resp_Ack       <= r.Resp_Ack;
584	    Resp_Data      <= r.Resp_Data;
585	    Resp_SeqErr    <= r.Resp_SeqErr;
586	    Status_CmdTo   <= r.Status_CmdTo;
587	
588	    -- Internal Tri-State buffers
589	    g_int_tristate : if InternalTriState_g generate
590	        I2c_Scl   <= 'Z' when r.SclOut = '1' else '0';
591	        I2c_Sda   <= 'Z' when r.SdaOut = '1' else '0';
592	        I2c_Scl_o <= '0';
593	        I2c_Sda_o <= '0';
594	        I2c_Scl_t <= '1';
595	        I2c_Sda_t <= '1';
596	    end generate;
597	
598	    -- External Tri-State buffers
599	    g_ext_tristatte : if not InternalTriState_g generate
600	        I2c_Scl_o <= r.SclOut;
601	        I2c_Sda_o <= r.SdaOut;
602	        I2c_Scl_t <= r.SclOut;
603	        I2c_Sda_t <= r.SdaOut;
604	        I2c_Scl   <= '0';
605	        I2c_Sda   <= '0';
606	    end generate;
607	
608	    -----------------------------------------------------------------------------------------------
609	    -- Sequential Proccess
610	    -----------------------------------------------------------------------------------------------
611	    p_seq : process (Clk) is
612	    begin
613	        if rising_edge(Clk) then
614	            r <= r_next;
615	            if Rst = '1' then
616	                r.Status_BusBusy <= '0';
617	                r.Cmd_Ready      <= '0';
618	                r.SclLast        <= '1';
619	                r.SdaLast        <= '1';
620	                r.BusBusyToCnt   <= (others => '0');
621	                r.Fsm            <= BusIdle_s;
622	                r.SclOut         <= '1';
623	                r.SdaOut         <= '1';
624	                r.Resp_Valid     <= '0';
625	            end if;
626	        end if;
627	    end process;
628	
629	    -----------------------------------------------------------------------------------------------
630	    -- Component Instantiations
631	    -----------------------------------------------------------------------------------------------
632	    I2cScl_Input <= to01X(I2c_Scl) when InternalTriState_g else I2c_Scl_i;
633	    I2cSda_Input <= to01X(I2c_Sda) when InternalTriState_g else I2c_Sda_i;
634	
635	    i_sync : entity work.olo_intf_sync
636	        generic map (
637	            Width_g     => 2
638	        )
639	        port map (
640	            Clk             => Clk,
641	            DataAsync(0)    => I2cScl_Input,
642	            DataAsync(1)    => I2cSda_Input,
643	            DataSync(0)     => I2cScl_Sync,
644	            DataSync(1)     => I2cSda_Sync
645	        );
646	
647	end architecture;
648

