30	
31	---------------------------------------------------------------------------------------------------
32	-- Entity
33	---------------------------------------------------------------------------------------------------
34	-- vunit: run_all_in_same_sim
35	entity olo_intf_i2c_master_tb is
36	    generic (
37	        BusFrequency_g              : integer := 100_000;
38	        ClkDiv_g                    : integer := 1;
39	        ClkDivBits_g                : integer := 0;
40	        InternalTriState_g          : boolean := true;
41	        runner_cfg                  : string
42	    );
43	end entity;
44	
45	architecture sim of olo_intf_i2c_master_tb is
46	
47	    -----------------------------------------------------------------------------------------------
48	    -- Fixed Generics
49	    -----------------------------------------------------------------------------------------------
50	    -- The ClkDivNonZero_c ensures that the clock division is never zero when using it to calculate the period and timeouts.
51	    constant ClkDivNonZero_c  : integer := choose(ClkDiv_g = 0, 1, ClkDiv_g);
52	    constant Scl_Period_c     : time    := (1 sec) / (real(BusFrequency_g) / real(ClkDivNonZero_c));
53	    constant BusBusyTimeout_c : real    := 200.0/ (real(BusFrequency_g) / real(ClkDivNonZero_c));
54	    constant CmdTimeout_c     : real    := 50.0/ (real(BusFrequency_g) / real(ClkDivNonZero_c));
55	
56	    -----------------------------------------------------------------------------------------------
57	    -- TB Defnitions
58	    -----------------------------------------------------------------------------------------------
59	    constant Clk_Frequency_c : real := 1.0e6*16.0;
60	    constant Clk_Period_c    : time := (1 sec) / Clk_Frequency_c;
61	
62	    -----------------------------------------------------------------------------------------------
63	    -- Interface Signals
64	    -----------------------------------------------------------------------------------------------
65	    -- Contral Sginal
66	    signal Clk            : std_logic := '0';
67	    signal Rst            : std_logic := '0';
68	    -- Command Interface
69	    signal Cmd_Ready      : std_logic;
70	    signal Cmd_Valid      : std_logic := '0';
71	    signal Cmd_Command    : std_logic_vector(2 downto 0);
72	    signal Cmd_Data       : std_logic_vector(7 downto 0);
73	    signal Cmd_Ack        : std_logic;
74	    signal Cmd_ClkDiv     : std_logic_vector(ClkDivBits_g - 1 downto 0);
75	    -- Response Interface
76	    signal Resp_Valid     : std_logic;
77	    signal Resp_Command   : std_logic_vector(2 downto 0);
78	    signal Resp_Data      : std_logic_vector(7 downto 0);
79	    signal Resp_Ack       : std_logic;
80	    signal Resp_ArbLost   : std_logic;
81	    signal Resp_SeqErr    : std_logic;
82	    -- Status Interface
83	    signal Status_BusBusy : std_logic;
84	    signal Status_CmdTo   : std_logic;
85	    -- I2c Interface with internal Tri-State
86	    signal I2c_Scl        : std_logic := 'Z';
87	    signal I2c_Sda        : std_logic := 'Z';
88	    -- I2c Interface with external Tri-State
89	    signal I2c_Scl_i      : std_logic := '0';
90	    signal I2c_Scl_o      : std_logic;
91	    signal I2c_Scl_t      : std_logic;
92	    signal I2c_Sda_i      : std_logic := '0';
93	    signal I2c_Sda_o      : std_logic;
94	    signal I2c_Sda_t      : std_logic;
95	
96	    -----------------------------------------------------------------------------------------------
97	    -- TB Defnitions
98	    -----------------------------------------------------------------------------------------------
99	
100	    -- *** Verification Compnents ***
101	    constant I2cSlave_c : olo_test_i2c_t := new_olo_test_i2c (
102	        bus_frequency => real(BusFrequency_g) / real(ClkDivNonZero_c)
103	    );
104	
105	    constant I2cMaster_c : olo_test_i2c_t := new_olo_test_i2c (
106	        bus_frequency => real(BusFrequency_g) / real(ClkDivNonZero_c)
107	    );
108	
109	    -- *** Internal Messaging ***
110	    constant CmdQueue_c : queue_t    := new_queue;
111	    constant CmdMsg_c   : msg_type_t := new_msg_type("I2C Command");
112	
113	    procedure pushCommand (
114	        Command : std_logic_vector(2 downto 0);
115	        SetData : boolean                      := false;
116	        Data    : std_logic_vector(7 downto 0) := (others => '0');
117	        SetAck  : boolean                      := false;
118	        Ack     : std_logic                    := '1';
119	        Delay   : time                         := 0 ns) is
120	        variable Msg_v : msg_t := new_msg(CmdMsg_c);
121	    begin
122	        push(Msg_v, Command);
123	        push(Msg_v, SetData);
124	        push(Msg_v, Data);
125	        push(Msg_v, SetAck);
126	        push(Msg_v, Ack);
127	        push(Msg_v, Delay);
128	        push(CmdQueue_c, Msg_v);
129	    end procedure;
130	
131	    constant NoData_c : std_logic_vector(7 downto 0) := (others => 'X');
132	
133	    procedure checkResp (
134	        Command : std_logic_vector(2 downto 0);
135	        Data    : std_logic_vector(7 downto 0) := NoData_c;
136	        Ack     : std_logic                    := 'X';
137	        ArbLost : std_logic                    := '0';
138	        SeqErr  : std_logic                    := '0';
139	        Msg     : string                       := "") is
140	    begin
141	        wait until rising_edge(Clk) and Resp_Valid = '1';
142	        check_equal(Resp_Command, Command, "Wrong Resp_Command - " & Msg);
143	        if Data /= NoData_c then
144	            check_equal(Resp_Data, Data, "Wrong Resp_Data - " & Msg);
145	        end if;
146	        if Ack /= 'X' then
147	            check_equal(Resp_Ack, Ack, "Wrong Resp_Ack - " & Msg);
148	        end if;
149	        check_equal(Resp_ArbLost, ArbLost, "Wrong Resp_ArbLost - " & Msg);
150	        check_equal(Resp_SeqErr, SeqErr, "Wrong Resp_SeqErr - " & Msg);
151	    end procedure;
152	
153	begin
154	
155	    -----------------------------------------------------------------------------------------------
156	    -- TB Control
157	    -----------------------------------------------------------------------------------------------
158	    test_runner_watchdog(runner, 50 ms);
159	
160	    p_control : process is
161	        variable StartTime_v : time;
162	    begin
163	        test_runner_setup(runner, runner_cfg);
164	
165	        while test_suite loop
166	
167	            -- Reset
168	            wait until rising_edge(Clk);
169	            Rst         <= '1';
170	            wait for 1 us;
171	            wait until rising_edge(Clk);
172	            Rst         <= '0';
173	            wait until rising_edge(Clk);
174	            StartTime_v := now;
175	
176	            -- *** Basics ***
177	            if run("ResetValues") then
178	                wait for 1 us;
179	                check_equal(Cmd_Ready, '1', "Cmd_Ready");
180	                check_equal(Resp_Valid, '0', "Cmd_Valid");
181	                check_equal(Status_BusBusy, '0', "Status_BusBusy");
182	                check_equal(Status_CmdTo, '0', "Status_CmdTo");
183	                check_equal(I2c_Scl, 'H', "I2c_Scl");
184	                check_equal(I2c_Sda, 'H', "I2c_Sda");
185	            end if;
186	
187	            if run("StartRepstartStop") then
188	                -- I2C Endpoint
189	                i2c_expect_start(net, I2cSlave_c);
190	                i2c_expect_repeated_start(net, I2cSlave_c);
191	                i2c_expect_stop(net, I2cSlave_c);
192	                -- Commands
193	                pushCommand(I2cCmd_Start_c);
194	                pushCommand(I2cCmd_RepStart_c);
195	                pushCommand(I2cCmd_Stop_c);
196	                -- Check responses (blocking)
197	                checkResp(I2cCmd_Start_c);
198	                check_equal(Status_BusBusy, '1', "Status_BusBusy 1");
199	                checkResp(I2cCmd_RepStart_c);
200	                checkResp(I2cCmd_Stop_c);
201	                wait_for_value_stdl(Status_BusBusy, '0', 10 us, "Status_BusBusy 0");
202	                check_last_activity(Status_CmdTo, now-StartTime_v, 0, "Status_CmdTo");
203	            end if;
204	
205	            -- *** Write ***
206	            if run("Write1bAck") then
207	                -- I2C Endpoint
208	                i2c_expect_start(net, I2cSlave_c);
209	                i2c_expect_rx_byte(net, I2cSlave_c, 16#42#);
210	                i2c_expect_stop(net, I2cSlave_c);
211	                -- Commands
212	                pushCommand(I2cCmd_Start_c);
213	                pushCommand(I2cCmd_Send_c, true, X"42", true);
214	                pushCommand(I2cCmd_Stop_c);
215	                -- Check responses (blocking)
216	                checkResp(I2cCmd_Start_c);
217	                check_equal(Status_BusBusy, '1', "Status_BusBusy 1");
218	                checkResp(I2cCmd_Send_c, X"42", '1');
219	                checkResp(I2cCmd_Stop_c);
220	                wait_for_value_stdl(Status_BusBusy, '0', 10 us, "Status_BusBusy 0");
221	                check_last_activity(Status_CmdTo, now-StartTime_v, 0, "Status_CmdTo");
222	            end if;
223	
224	            if run("Write2bAckNack") then
225	                -- I2C Endpoint
226	                i2c_expect_start(net, I2cSlave_c);
227	                i2c_expect_rx_byte(net, I2cSlave_c, 16#42#, msg => "byte 0");
228	                i2c_expect_rx_byte(net, I2cSlave_c, 16#53#, I2c_NACK, msg => "byte 1");
229	                i2c_expect_stop(net, I2cSlave_c);
230	                -- Commands
231	                pushCommand(I2cCmd_Start_c);
232	                pushCommand(I2cCmd_Send_c, true, X"42", true);
233	                pushCommand(I2cCmd_Send_c, true, X"53", true);
234	                pushCommand(I2cCmd_Stop_c);
235	                -- Check responses (blocking)
236	                checkResp(I2cCmd_Start_c);
237	                check_equal(Status_BusBusy, '1', "Status_BusBusy 1");
238	                checkResp(I2cCmd_Send_c, Ack => '1');
239	                checkResp(I2cCmd_Send_c, Ack => '0');
240	                checkResp(I2cCmd_Stop_c);
241	                wait_for_value_stdl(Status_BusBusy, '0', 10 us, "Status_BusBusy 0");
242	                check_last_activity(Status_CmdTo, now-StartTime_v, 0, "Status_CmdTo");
243	            end if;
244	
245	            -- *** Read ***
246	            if run("Read1bAck") then
247	                -- I2C Endpoint
248	                i2c_expect_start(net, I2cSlave_c);
249	                i2c_push_tx_byte(net, I2cSlave_c, 16#36#);
250	                i2c_expect_stop(net, I2cSlave_c);
251	                -- Commands
252	                pushCommand(I2cCmd_Start_c);
253	                pushCommand(I2cCmd_Receive_c, false, SetAck => true);
254	                pushCommand(I2cCmd_Stop_c);
255	                -- Check responses (blocking)
256	                checkResp(I2cCmd_Start_c);
257	                check_equal(Status_BusBusy, '1', "Status_BusBusy 1");
258	                checkResp(I2cCmd_Receive_c, Data => X"36");
259	                checkResp(I2cCmd_Stop_c);
260	                wait_for_value_stdl(Status_BusBusy, '0', 10 us, "Status_BusBusy 0");
261	                check_last_activity(Status_CmdTo, now-StartTime_v, 0, "Status_CmdTo");
262	            end if;
263	
264	            if run("Read2bAckNack") then
265	                -- I2C Endpoint
266	                i2c_expect_start(net, I2cSlave_c);
267	                i2c_push_tx_byte(net, I2cSlave_c, 16#36#, msg => "byte 0");
268	                i2c_push_tx_byte(net, I2cSlave_c, 16#47#, I2c_NACK, msg => "byte 1");
269	                i2c_expect_stop(net, I2cSlave_c);
270	                -- Commands
271	                pushCommand(I2cCmd_Start_c);
272	                pushCommand(I2cCmd_Receive_c, false, SetAck => true, Ack => '1');
273	                pushCommand(I2cCmd_Receive_c, false, SetAck => true, Ack => '0');
274	                pushCommand(I2cCmd_Stop_c);
275	                -- Check responses (blocking)
276	                checkResp(I2cCmd_Start_c);
277	                check_equal(Status_BusBusy, '1', "Status_BusBusy 1");
278	                checkResp(I2cCmd_Receive_c, Data => X"36");
279	                checkResp(I2cCmd_Receive_c, Data => X"47");
280	                checkResp(I2cCmd_Stop_c);
281	                wait_for_value_stdl(Status_BusBusy, '0', 10 us, "Status_BusBusy 0");
282	                check_last_activity(Status_CmdTo, now-StartTime_v, 0, "Status_CmdTo");
283	            end if;
284	
285	            -- *** Test Write then Read ***
286	            if run("WriteThenRead") then
287	                -- I2C Endpoint
288	                i2c_expect_start(net, I2cSlave_c);
289	                i2c_expect_rx_byte(net, I2cSlave_c, 16#42#, msg => "byte rx");
