685	                I2cFrequency_g      => real(BusFrequency_g),
686	                ClkDivBits_g        => ClkDivBits_g,
687	                BusBusyTimeout_g    => BusBusyTimeout_c,
688	                CmdTimeout_g        => CmdTimeout_c,
689	                InternalTriState_g  => InternalTriState_g,
690	                DisableAsserts_g    => true
691	            )
692	            port map (
693	                -- Control Signals
694	                Clk             => Clk,
695	                Rst             => Rst,
696	                -- Command Interface
697	                Cmd_Ready       => Cmd_Ready,
698	                Cmd_Valid       => Cmd_Valid,
699	                Cmd_Command     => Cmd_Command,
700	                Cmd_Data        => Cmd_Data,
701	                Cmd_Ack         => Cmd_Ack,
702	                Cmd_ClkDiv      => Cmd_ClkDiv,
703	                -- Response Interface
704	                Resp_Valid      => Resp_Valid,
705	                Resp_Command    => Resp_Command,
706	                Resp_Data       => Resp_Data,
707	                Resp_Ack        => Resp_Ack,
708	                Resp_ArbLost    => Resp_ArbLost,
709	                Resp_SeqErr     => Resp_SeqErr,
710	                -- Status Interface
711	                Status_BusBusy  => Status_BusBusy,
712	                Status_CmdTo    => Status_CmdTo,
713	                -- I2c Interface with internal Tri-State
714	                I2c_Scl         => I2c_Scl,
715	                I2c_Sda         => I2c_Sda
716	            );
717	
718	    end generate;
719	
720	    g_external_tristate : if InternalTriState_g = false generate
721	
722	        i_dut : entity olo.olo_intf_i2c_master
723	            generic map (
724	                ClkFrequency_g      => Clk_Frequency_c,
725	                I2cFrequency_g      => real(BusFrequency_g),
726	                ClkDivBits_g        => ClkDivBits_g,
727	                BusBusyTimeout_g    => BusBusyTimeout_c,
728	                CmdTimeout_g        => CmdTimeout_c,
729	                InternalTriState_g  => InternalTriState_g,
730	                DisableAsserts_g    => true
731	            )
732	            port map (
733	                -- Control Signals
734	                Clk             => Clk,
735	                Rst             => Rst,
736	                -- Command Interface
737	                Cmd_Ready       => Cmd_Ready,
738	                Cmd_Valid       => Cmd_Valid,
739	                Cmd_Command     => Cmd_Command,
740	                Cmd_Data        => Cmd_Data,
741	                Cmd_Ack         => Cmd_Ack,
742	                Cmd_ClkDiv      => Cmd_ClkDiv,
743	                -- Response Interface
744	                Resp_Valid      => Resp_Valid,
745	                Resp_Command    => Resp_Command,
746	                Resp_Data       => Resp_Data,
747	                Resp_Ack        => Resp_Ack,
748	                Resp_ArbLost    => Resp_ArbLost,
749	                Resp_SeqErr     => Resp_SeqErr,
750	                -- Status Interface
751	                Status_BusBusy  => Status_BusBusy,
752	                Status_CmdTo    => Status_CmdTo,
753	                -- I2c Interface with internal Tri-State
754	                I2c_Scl_i       => I2c_Scl_i,
755	                I2c_Scl_t       => I2c_Scl_t,
756	                I2c_Scl_o       => I2c_Scl_o,
757	                I2c_Sda_i       => I2c_Sda_i,
758	                I2c_Sda_t       => I2c_Sda_t,
759	                I2c_Sda_o       => I2c_Sda_o
760	            );
761	
762	        I2c_Scl   <= 'Z' when I2c_Scl_t = '1' else I2c_Scl_o;
763	        I2c_Sda   <= 'Z' when I2c_Sda_t = '1' else I2c_Sda_o;
764	        I2c_Scl_i <= to01X(I2c_Scl);
765	        I2c_Sda_i <= to01X(I2c_Sda);
766	
767	    end generate;
768	
769	    -----------------------------------------------------------------------------------------------
770	    -- Verification Components
771	    -----------------------------------------------------------------------------------------------
772	    vc_slave : entity work.olo_test_i2c_vc
773	        generic map (
774	            Instance => I2cSlave_c
775	        )
776	        port map (
777	            Scl   => I2c_Scl,
778	            Sda   => I2c_Sda
779	        );
780	
781	    vc_master : entity work.olo_test_i2c_vc
782	        generic map (
783	            Instance => I2cMaster_c
784	        )
785	        port map (
786	            Scl   => I2c_Scl,
787	            Sda   => I2c_Sda
788	        );
789	
790	    p_vc_cm : process is
791	        variable Msg_v     : msg_t;
792	        variable MsgType_v : msg_type_t;
793	        variable Command_v : std_logic_vector(2 downto 0);
794	        variable SetData_v : boolean;
795	        variable Data_v    : std_logic_vector(7 downto 0);
796	        variable SetAck_v  : boolean;
797	        variable Ack_v     : std_logic;
798	        variable Delay_v   : time;
799	    begin
800	        -- Initialize
801	        Cmd_Valid   <= '0';
802	        Cmd_Command <= (others => 'X');
803	        Cmd_Data    <= (others => 'X');
804	        Cmd_Ack     <= 'X';
805	        Cmd_ClkDiv  <= (others => 'X');
806	
807	        -- loop messages
808	        loop
809	            -- wait until message available
810	            if is_empty(CmdQueue_c) then
811	                wait until not is_empty(CmdQueue_c) and rising_edge(Clk);
812	            end if;
813	            -- get message
814	            Msg_v     := pop(CmdQueue_c);
815	            MsgType_v := message_type(Msg_v);
816	            -- process message
817	            if MsgType_v = CmdMsg_c then
818	                -- pop information
819	                Command_v := pop(Msg_v);
820	                SetData_v := pop(Msg_v);
821	                Data_v    := pop(Msg_v);
822	                SetAck_v  := pop(Msg_v);
823	                Ack_v     := pop(Msg_v);
824	                Delay_v   := pop(Msg_v);
825	
826	                -- Send command
827	                if Delay_v > 0 ns then
828	                    wait for Delay_v;
829	                    wait until rising_edge(Clk);
830	                end if;
831	                Cmd_Valid   <= '1';
832	                Cmd_Command <= Command_v;
833	                if SetData_v then
834	                    Cmd_Data <= Data_v;
835	                end if;
836	                if SetAck_v then
837	                    Cmd_Ack <= Ack_v;
838	                end if;
839	                -- Do not set ClkDiv on any other command than start
840	                if ClkDivBits_g > 0 and Command_v = I2cCmd_Start_c then
841	                    Cmd_ClkDiv <= std_logic_vector(to_unsigned(ClkDiv_g, ClkDivBits_g));
842	                end if;
843	                wait until rising_edge(Clk) and Cmd_Ready = '1';
844	                Cmd_Valid   <= '0';
845	                Cmd_Command <= (others => 'X');
846	                Cmd_Data    <= (others => 'X');
847	                Cmd_Ack     <= 'X';
848	                Cmd_ClkDiv  <= (others => 'X');
849	            else
850	                error("Unexpected message type in vc_cmd");
851	            end if;
852	        end loop;
853	
854	    end process;
855	
856	end architecture;
