25	package olo_test_i2c_pkg is
26	
27	    -- *** Constants ***
28	    constant i2c_ack  : std_logic := '0';
29	    constant i2c_nack : std_logic := '1';
30	
31	    type i2c_transaction_t is (i2c_read, i2c_write);
32	
33	    -- *** VUnit instance type ***
34	    type olo_test_i2c_t is record
35	        p_actor       : actor_t;
36	        bus_frequency : real;
37	    end record;
38	
39	    -- *** Master Operations ***
40	
41	    -- Send start (and switch to master operation mode)
42	    procedure i2c_push_start (
43	        signal net : inout network_t;
